import type { UmbCollectionRepository } from '@umbraco-cms/backoffice/collection';
import type { UmbControllerHost } from '@umbraco-cms/backoffice/controller-api';
import { FormsDataSourceTypeCollectionServerDataSource } from './datasource-type-collection.server.data-source.js';

export class FormsDataSourceTypeCollectionRepository implements UmbCollectionRepository {
	#collectionSource: FormsDataSourceTypeCollectionServerDataSource;

	constructor(host: UmbControllerHost) {
		this.#collectionSource = new FormsDataSourceTypeCollectionServerDataSource(host);
	}

	async requestCollection() {
		return this.#collectionSource.getCollection();
	}

	destroy(): void {}
}

export default FormsDataSourceTypeCollectionRepository;
